import { useEffect, useRef, useState } from "react";
import { v4 as uuidv4 } from "uuid";

type Msg = {
  role: "user" | "ai";
  text?: string;
  images?: string[];
};

type Chat = {
  id: string;
  title: string;
  messages: Msg[];
};

export default function Home() {
  const [input, setInput] = useState("");
  const [images, setImages] = useState<string[]>([]);
  const [messages, setMessages] = useState<Msg[]>([]);
  const [chats, setChats] = useState<Chat[]>([]);
  const [search, setSearch] = useState("");
  const [loading, setLoading] = useState(false);
  const [menuOpen, setMenuOpen] = useState<string | null>(null);
  const [dragging, setDragging] = useState(false);

  const [chatId, setChatId] = useState(uuidv4());
  const bottomRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages]);

  useEffect(() => {
    cargarChats();
  }, []);

  const cargarChats = async () => {
    try {
      const res = await fetch("/api/chat");
      const data = await res.json();
      setChats(Array.isArray(data) ? data : []);
    } catch {
      setChats([]);
    }
  };

  const nuevoChat = () => {
    setMessages([]);
    setInput("");
    setImages([]);
    setChatId(uuidv4());
  };

  const abrirChat = (chat: Chat) => {
    setChatId(chat.id);
    setMessages(chat.messages);
  };

  const eliminarChat = async (id: string) => {
    await fetch(`/api/chat?id=${id}`, { method: "DELETE" });
    setChats((prev) => prev.filter((c) => c.id !== id));
    if (id === chatId) nuevoChat();
  };

  const compartirChat = async (chat: Chat) => {
    await navigator.clipboard.writeText(JSON.stringify(chat, null, 2));
    alert("Copiado ✅");
  };

  const handlePaste = (e: React.ClipboardEvent<HTMLTextAreaElement>) => {
    for (const item of e.clipboardData.items) {
      if (item.type.includes("image")) {
        const file = item.getAsFile();
        if (!file) continue;

        const reader = new FileReader();
        reader.onload = () =>
          setImages((prev) => [...prev, reader.result as string]);
        reader.readAsDataURL(file);
      }
    }
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    setDragging(false);

    const files = Array.from(e.dataTransfer.files);

    files.forEach((file) => {
      const reader = new FileReader();
      reader.onload = () =>
        setImages((prev) => [...prev, reader.result as string]);
      reader.readAsDataURL(file);
    });
  };

  const enviarMensaje = async () => {
    if (!input.trim() && images.length === 0) return;

    setLoading(true);

    setMessages((prev) => [
      ...prev,
      { role: "user", text: input, images },
    ]);

    const formData = new FormData();
    formData.append("chatId", chatId);
    formData.append("message", input);

    images.forEach((img, i) => {
      formData.append(`image_${i}`, img);
    });

    setInput("");
    setImages([]);

    try {
      const res = await fetch("/api/chat", {
        method: "POST",
        body: formData,
      });

      const data = await res.json();

      // ✅ streaming
      const words = (data.reply || "...").split(" ");
      let current = "";

      for (let i = 0; i < words.length; i++) {
        current += words[i] + " ";
        await new Promise((r) => setTimeout(r, 20));

        setMessages((prev) => {
          const last = prev[prev.length - 1];

          if (last?.role === "ai") {
            const copy = [...prev];
            copy[copy.length - 1] = { role: "ai", text: current };
            return copy;
          }

          return [...prev, { role: "ai", text: current }];
        });
      }

      cargarChats();
    } finally {
      setLoading(false);
    }
  };

  return (
    <main
      className="h-screen flex bg-[#030812] text-white"
      onDragOver={(e) => {
        e.preventDefault();
        setDragging(true);
      }}
      onDragLeave={() => setDragging(false)}
      onDrop={handleDrop}
    >

      {/* SIDEBAR */}
      <div className="w-[300px] bg-[#0d131d] border-r border-[#202938] flex flex-col">

        <div className="flex flex-col items-center pt-6 pb-6">
          <img src="/logo.png" className="w-16 h-16" />
          <p className="text-green-400 text-sm mt-2">
            La salud es para todos
          </p>
        </div>

        <div className="px-4 space-y-2">
          <button onClick={nuevoChat} className="btn">➕ Nuevo chat</button>
          <button className="btn">🎨 Crear imagen</button>
          <button className="btn">📄 Analizar archivo</button>
          <button className="btn">📁 Proyectos</button>

          <input
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            placeholder="Buscar chats..."
            className="input"
          />
        </div>

        <div className="flex-1 overflow-y-auto px-3 mt-3">
          {chats
            .filter((c) =>
              c.title.toLowerCase().includes(search.toLowerCase())
            )
            .map((chat) => (
              <div key={chat.id} className="relative mb-2">

                <div className="flex justify-between bg-[#121824] p-3 rounded-xl">
                  <button onClick={() => abrirChat(chat)} className="flex-1 text-left">
                    {chat.title}
                  </button>

                  <button onClick={() => setMenuOpen(menuOpen === chat.id ? null : chat.id)}>
                    ⋮
                  </button>
                </div>

                {menuOpen === chat.id && (
                  <div className="absolute right-2 top-12 bg-[#0d131d] border rounded-xl w-48 z-50">
                    <button onClick={() => compartirChat(chat)} className="menu">📋 Compartir</button>
                    <button className="menu">✏️ Renombrar</button>
                    <button className="menu">📌 Anclar</button>
                    <button className="menu">📦 Archivar</button>
                    <button onClick={() => eliminarChat(chat.id)} className="menu text-red-500">🗑 Eliminar</button>
                  </div>
                )}
              </div>
            ))}
        </div>
      </div>

      {/* MAIN */}
      <div className="flex-1 flex flex-col">

        <div className="text-center mt-10">
          <h1 className="text-4xl font-bold text-green-400">
            Inteligencia Digna
          </h1>
          <p className="text-gray-400">by Salud Digna</p>
        </div>

        {messages.length === 0 && (
          <div className="flex-1 flex items-center justify-center">
            <div className="bg-[#121824] p-6 rounded-2xl text-center">
              <h2>¡Hola! Soy Inteligencia Digna</h2>
              <p className="text-gray-400 mt-2">
                ¿En qué puedo ayudarte hoy?
              </p>
            </div>
          </div>
        )}

        <div className="flex-1 overflow-y-auto p-6 max-w-2xl mx-auto w-full">
          {messages.map((m, i) => (
            <div key={i} className={m.role === "user" ? "text-right mb-4" : "mb-4"}>
              <div className={`inline-block p-3 rounded-xl ${
                m.role === "user" ? "bg-green-600" : "bg-[#121824]"
              }`}>
                {m.text}

                {m.images?.map((img, idx) => (
                  <img key={idx} src={img} className="mt-2 max-h-40 rounded-lg" />
                ))}
              </div>
            </div>
          ))}

          {loading && <div className="text-gray-400">Escribiendo...</div>}
          <div ref={bottomRef} />
        </div>

        <div className="p-4 border-t border-[#1f2632] max-w-2xl mx-auto w-full">

          {images.length > 0 && (
            <div className="flex gap-2 mb-2 flex-wrap">
              {images.map((img, i) => (
                <div key={i} className="relative">
                  <img src={img} className="h-16 rounded" />
                  <button
                    onClick={() =>
                      setImages((prev) => prev.filter((_, idx) => idx !== i))
                    }
                    className="absolute top-0 right-0 bg-red-500 text-xs px-1 rounded"
                  >
                    ✕
                  </button>
                </div>
              ))}
            </div>
          )}

          <form
            onSubmit={(e) => {
              e.preventDefault();
              enviarMensaje();
            }}
            className="flex gap-2"
          >
            <textarea
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onPaste={handlePaste}
              placeholder="Escribe o pega imágenes..."
              className="input flex-1 resize-none"
              rows={1}
              onKeyDown={(e) => {
                if (e.key === "Enter" && !e.shiftKey) {
                  e.preventDefault();
                  enviarMensaje();
                }
              }}
            />

            <button className="sendBtn">➤</button>
          </form>
        </div>

      </div>

      <style jsx>{`
        .btn {
          width: 100%;
          background: #121824;
          padding: 12px;
          border-radius: 12px;
          text-align: left;
        }

        .input {
          width: 100%;
          padding: 12px;
          background: #121824;
          border-radius: 12px;
          outline: none;
        }

        .menu {
          padding: 10px;
          width: 100%;
          text-align: left;
        }

        .menu:hover {
          background: #121824;
        }

        .sendBtn {
          background: #22c55e;
          padding: 0 16px;
          border-radius: 12px;
        }

        /* ✅ SCROLLBAR PRO */
        ::-webkit-scrollbar {
          width: 8px;
        }

        ::-webkit-scrollbar-track {
          background: #030812;
        }

        ::-webkit-scrollbar-thumb {
          background: #1e293b;
          border-radius: 10px;
        }

        ::-webkit-scrollbar-thumb:hover {
          background: #334155;
        }
      `}</style>
    </main>
  );
}
